if (! function_exists('data_enricher')) {
    function data_enricher($table, $url_template, $target_column, $db_name = null, $response_path = null, $limit = null, $timeout = null, $sleep_ms = null)
    {
        // Data Enricher — iterate DB rows, call external API, merge results back
        $db_name = $db_name ?? 'harvested_data.sqlite';
        $table = $table ?? '';
        $url_template = $url_template ?? '';
        $response_path = $response_path ?? 'all';
        $target_column = $target_column ?? '';
        $limit = $limit ?? 10;
        $timeout = $timeout ?? 15;
        $sleep_ms = $sleep_ms ?? 0;

        if (empty($table) || empty($url_template) || empty($target_column)) {
            return ['error' => 'table, url_template, and target_column are required', 'success' => false];
        }
        $limit = max(0, min(1000, (int)$limit));
        $timeout = max(5, min(30, (int)$timeout));
        $sleep_ms = max(0, min(60000, (int)$sleep_ms));

        $db_path = __DIR__ . '/../workspace/' . basename($db_name);
        if (!file_exists($db_path)) {
            return ['error' => "Database not found: $db_name", 'success' => false];
        }

        try {
            $pdo = new PDO("sqlite:$db_path");
            $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            
            // Check table exists
            $check = $pdo->query("SELECT name FROM sqlite_master WHERE type='table' AND name=" . $pdo->quote($table));
            if (!$check->fetch()) {
                return ['error' => "Table '$table' not found in database", 'success' => false];
            }
            
            // Get table info
            $col_info = $pdo->query("PRAGMA table_info(" . $pdo->quote($table) . ")")->fetchAll(PDO::FETCH_ASSOC);
            $existing_cols = array_column($col_info, 'name');
            
            // Build the query
            $query = 'SELECT * FROM "' . $table . '"';
            if ($limit > 0) $query .= ' LIMIT ' . $limit;
            
            $rows = $pdo->query($query)->fetchAll(PDO::FETCH_ASSOC);
            
            if (empty($rows)) {
                return ['error' => 'No rows to process', 'success' => false];
            }
            
            // Add target column if it doesn't exist
            if (!in_array($target_column, $existing_cols)) {
                $pdo->exec('ALTER TABLE "' . $table . '" ADD COLUMN "' . $target_column . '" TEXT');
            }
            
            $processed = 0;
            $errors = 0;
            $results = [];
            
            foreach ($rows as $row) {
                $pk_value = $row['id'] ?? $row['row_id'] ?? null;
                if ($pk_value === null) {
                    // Try first column
                    $first_col = $existing_cols[0] ?? null;
                    if ($first_col) $pk_value = $row[$first_col];
                }
                
                // Build URL from template
                $url = $url_template;
                foreach ($row as $col => $val) {
                    $url = str_replace('{{' . $col . '}}', urlencode((string)$val), $url);
                }
                
                // Call the API
                $ctx = stream_context_create([
                    'http' => [
                        'method' => 'GET',
                        'timeout' => $timeout,
                        'header' => "User-Agent: data_enricher/1.0\r\nAccept: application/json\r\n",
                        'ignore_errors' => true,
                    ],
                    'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                ]);
                
                $start = microtime(true);
                $response = @file_get_contents($url, false, $ctx);
                $elapsed_ms = round((microtime(true) - $start) * 1000);
                
                $status = 200;
                if (isset($http_response_header)) {
                    foreach ($http_response_header as $h) {
                        if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) $status = (int)$m[1];
                    }
                }
                
                $enriched_value = null;
                $row_error = null;
                
                if ($response === false) {
                    $err = error_get_last();
                    $row_error = 'HTTP error: ' . ($err['message'] ?? 'unknown');
                    $errors++;
                } elseif ($status >= 400) {
                    $row_error = "HTTP $status";
                    $errors++;
                } else {
                    if ($response_path === 'all') {
                        $enriched_value = mb_substr($response, 0, 10000);
                    } else {
                        $decoded = @json_decode($response, true);
                        if ($decoded === null) {
                            $row_error = 'Invalid JSON response';
                            $errors++;
                        } else {
                            // Navigate dot path
                            $parts = explode('.', $response_path);
                            $current = $decoded;
                            $found = true;
                            foreach ($parts as $part) {
                                if (is_array($current) && array_key_exists($part, $current)) {
                                    $current = $current[$part];
                                } else {
                                    $found = false;
                                    break;
                                }
                            }
                            if ($found) {
                                $enriched_value = is_array($current) ? json_encode($current, JSON_UNESCAPED_UNICODE) : (string)$current;
                            } else {
                                $row_error = "Path '$response_path' not found in response";
                                $errors++;
                            }
                        }
                    }
                }
                
                // Store result
                if ($enriched_value !== null) {
                    $update_sql = 'UPDATE "' . $table . '" SET "' . $target_column . '" = ? WHERE rowid = ?';
                    // Try primary key
                    if ($pk_value !== null) {
                        $pk_col = 'id';
                        if (!in_array('id', $existing_cols)) $pk_col = 'row_id';
                        if (!in_array($pk_col, $existing_cols)) $pk_col = $existing_cols[0];
                        $update_sql = 'UPDATE "' . $table . '" SET "' . $target_column . '" = ? WHERE "' . $pk_col . '" = ?';
                    }
                    
                    $stmt = $pdo->prepare($update_sql);
                    $stmt->execute([$enriched_value, $pk_value]);
                    $processed++;
                }
                
                $results[] = [
                    'row_id' => $pk_value,
                    'url' => $url,
                    'status' => $status,
                    'response_time_ms' => $elapsed_ms,
                    'enriched' => $enriched_value !== null,
                    'error' => $row_error,
                ];
                
                // Rate limiting sleep
                if ($sleep_ms > 0 && count($results) < count($rows)) {
                    usleep($sleep_ms * 1000);
                }
            }
            
            // Summary
            $success_count = count(array_filter($results, fn($r) => $r['enriched']));
            return [
                'success' => true,
                'table' => $table,
                'target_column' => $target_column,
                'rows_processed' => count($results),
                'rows_enriched' => $success_count,
                'errors' => $errors,
                'details' => $results,
            ];
            
        } catch (Exception $e) {
            return ['error' => 'Database error: ' . $e->getMessage(), 'success' => false];
        }
    }
